import json
from pathlib import Path

# --- Basic try/except ---
try:
    result = 10 / 0
except ZeroDivisionError as e:
    print(f"Cannot divide by zero: {e}")
    result = float("inf")

# --- Multiple except clauses ---
def parse_json_file(path: str) -> dict:
    try:
        text = Path(path).read_text(encoding="utf-8")
        return json.loads(text)
    except FileNotFoundError:
        raise FileNotFoundError(f"Config file not found: {path}")
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON in {path}: {e}") from e

# --- try/except/else/finally ---
def read_config(path: str) -> dict | None:
    fh = None
    try:
        fh = open(path, "r")
        data = json.load(fh)
    except FileNotFoundError:
        print(f"File {path} not found, using defaults")
        return None
    except json.JSONDecodeError as e:
        print(f"JSON parse error: {e}")
        return None
    else:
        # Runs only if no exception was raised in try
        print(f"Config loaded successfully: {len(data)} keys")
        return data
    finally:
        # Always runs — cleanup here
        if fh:
            fh.close()

# --- Raising exceptions ---
def validate_age(age: int) -> None:
    if not isinstance(age, int):
        raise TypeError(f"Expected int, got {type(age).__name__}")
    if age < 0 or age > 150:
        raise ValueError(f"Age {age} is out of realistic range")

# --- Exception chaining (raise ... from ...) ---
def load_model_config(path: str) -> dict:
    try:
        return parse_json_file(path)
    except (FileNotFoundError, ValueError) as e:
        raise RuntimeError("Could not load model configuration") from e

# --- Context managers as clean try/finally alternative ---
with open("data.txt", "w") as f:
    f.write("hello")   # file auto-closed even if an error occurs

import time
import random
from typing import Any

class RateLimitError(Exception):
    pass

class APIError(Exception):
    pass

def call_llm_api(prompt: str) -> dict:
    """Simulate an LLM API call that occasionally fails."""
    r = random.random()
    if r < 0.3:
        raise RateLimitError("429 Too Many Requests")
    if r < 0.4:
        raise APIError("503 Service Unavailable")
    return {"content": f"Response to: {prompt[:20]}..."}

def call_with_retry(
    prompt: str,
    max_attempts: int = 5,
    base_delay: float = 1.0,
) -> dict | None:
    """Call the LLM API with exponential back-off retry."""
    last_error: Exception | None = None

    for attempt in range(1, max_attempts + 1):
        try:
            result = call_llm_api(prompt)
        except RateLimitError as e:
            last_error = e
            delay = base_delay * (2 ** (attempt - 1))  # exponential back-off
            print(f"Rate limited (attempt {attempt}/{max_attempts}). Waiting {delay:.1f}s")
            time.sleep(delay)
            continue
        except APIError as e:
            last_error = e
            print(f"API error (attempt {attempt}/{max_attempts}): {e}")
            if attempt < max_attempts:
                time.sleep(base_delay)
            continue
        except Exception as e:
            # Unexpected error — do not retry
            print(f"Unexpected error: {e}")
            raise
        else:
            # Success — no exception raised
            print(f"Succeeded on attempt {attempt}")
            return result
    else:
        # Loop completed without a break — all attempts failed
        print(f"All {max_attempts} attempts failed. Last error: {last_error}")
        return None

result = call_with_retry("What is the capital of France?", max_attempts=5)
if result:
    print(result["content"])
